<?php

defined('ABSPATH') || exit;

function stv_add_menu_item() {
    add_menu_page(
            'LiteCache - Suspicious Traffic Viewer',
            'LiteCache - STV',
            'manage_options',
            'litecache-stv',
            'litecache_stv_display_page',
            'data:image/svg+xml;base64,'
    );
    add_submenu_page(
            'litecache-stv',
            'LiteCache - STV Excludes',
            'Excludes',
            'manage_options',
            'litecache-stv-excludes',
            'litecache_stv_excludes_page',
    );
    add_submenu_page(
            'litecache-stv',
            'LiteCache - STV Settings',
            'Settings',
            'manage_options',
            'litecache-stv-settings',
            'litecache_stv_settings_page',
    );
}

add_action('admin_menu', 'stv_add_menu_item');

